const rawCall = $('Get Call').first().json;
const call = Array.isArray(rawCall) ? (rawCall[0] || {}) : (rawCall || {});
const callId = $('Webhook').first().json.body.call_id;
const transcript = (call.transcript_raw || '').trim();
const hasTranscript = transcript.length >= 50;
return [{ json: { call_id: callId, has_transcript: hasTranscript } }];

const ANTHROPIC_KEY = process.env.ANTHROPIC_API_KEY;
if (!ANTHROPIC_KEY) throw new Error('ANTHROPIC_API_KEY not set in n8n environment variables');
const SUPABASE_URL = 'https://fybvnwidpnxnouaukrnb.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZ5YnZud2lkcG54bm91YXVrcm5iIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3ODA2NjM2NSwiZXhwIjoyMDkzNjQyMzY1fQ.sCP7tiT6_Pc_nME6HqmfH5PUZjaNzrfl45R8JK6Ay4c';

async function callAnthropic(messages, system, maxTokens) {
  const res = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'x-api-key': ANTHROPIC_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    body: JSON.stringify({ model: 'claude-sonnet-4-6', max_tokens: maxTokens || 4000, system, messages }),
  });
  if (!res.ok) throw new Error('Anthropic error ' + res.status + ': ' + (await res.text()).substring(0, 200));
  const data = await res.json();
  return data.content[0].text;
}

async function sbFetch(path) {
  const res = await fetch(SUPABASE_URL + '/rest/v1/' + path, {
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY },
  });
  return res.json();
}

const { systemPrompt, userMessage } = $input.first().json;

// Turn 1: Identify rep and key moments
const turn1Raw = await callAnthropic(
  [{ role: 'user', content: 'From this call transcript, identify the internal sales rep first name and the 3 most critical moments that will determine call quality. Do NOT score yet. Respond with ONLY raw JSON, no markdown: {"rep_name":"string","key_moments":["string","string","string"]}\n\n' + userMessage }],
  'You analyze sales call transcripts. Return only raw JSON.',
  600
);
let repName = '';
let keyMoments = [];
try {
  const clean1 = turn1Raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  const t1 = JSON.parse(clean1);
  repName = (t1.rep_name || '').trim();
  keyMoments = Array.isArray(t1.key_moments) ? t1.key_moments : [];
} catch(e) {}

// Fetch rep history from Supabase
let repHistorySummary = 'No previous call history available.';
if (repName) {
  try {
    const members = await sbFetch('team_members?name=ilike.*' + encodeURIComponent(repName) + '*&select=id,name&limit=1');
    if (Array.isArray(members) && members[0]) {
      const memberId = members[0].id;
      const parts = await sbFetch('call_participants?team_member_id=eq.' + memberId + '&is_external=eq.false&select=calls(recorded_at,scorecards(overall_score,summary))&order=created_at.desc&limit=5');
      const history = (Array.isArray(parts) ? parts : [])
        .map(p => p.calls)
        .filter(c => c && c.scorecards && c.scorecards[0] != null && c.scorecards[0].overall_score != null)
        .map(c => '- ' + (c.recorded_at || '').substring(0, 10) + ': ' + c.scorecards[0].overall_score + '/10 — ' + (c.scorecards[0].summary || '').split('.')[0]);
      if (history.length > 0) repHistorySummary = members[0].name + "'s last " + history.length + ' scored calls:\n' + history.join('\n');
    }
  } catch(e) {}
}

// Turn 2: Contextual scoring with history
const turn2UserMsg = userMessage +
  '\n\n--- REP HISTORY ---\n' + repHistorySummary +
  '\n\n--- KEY MOMENTS ---\n' + keyMoments.map((m, i) => (i + 1) + '. ' + m).join('\n') +
  '\n\nNow score this call. Also add to your JSON: "rep_trajectory" (improving/declining/stable based on history) and "comparison_note" (one sentence vs baseline).';

const turn2Raw = await callAnthropic(
  [{ role: 'user', content: turn2UserMsg }],
  systemPrompt,
  4000
);

// Turn 3: Coaching synthesis
const turn3Raw = await callAnthropic(
  [
    { role: 'user', content: turn2UserMsg },
    { role: 'assistant', content: turn2Raw },
    { role: 'user', content: 'Provide a coaching synthesis as raw JSON only: {"manager_summary":"2-sentence manager summary","positive_reinforcement":"one specific strength to reinforce"}' }
  ],
  'You are a sales coaching assistant. Return only raw JSON.',
  500
);

// Merge Turn 3 into Turn 2 scorecard JSON
let cleanFinal = turn2Raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
try {
  const sc = JSON.parse(cleanFinal);
  try {
    const t3 = JSON.parse(turn3Raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim());
    if (t3.manager_summary) sc.manager_summary = t3.manager_summary;
    if (t3.positive_reinforcement) sc.positive_reinforcement = t3.positive_reinforcement;
  } catch(e) {}
  cleanFinal = JSON.stringify(sc);
} catch(e) {}

return [{ json: { text: cleanFinal } }];

const responseText = ($input.first().json.text || $input.first().json.content?.[0]?.text || '').trim();
const callId = $('Webhook').first().json.body.call_id;
const rawRubricPS = $('Get Active Rubric').first().json;
const rubric = Array.isArray(rawRubricPS) ? (rawRubricPS[0] || null) : (rawRubricPS || null);

let cleanText = responseText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

// Fallback: if model returned markdown prose, extract the embedded JSON object
if (!cleanText.startsWith('{')) {
  const start = cleanText.indexOf('{');
  const end = cleanText.lastIndexOf('}');
  if (start !== -1 && end > start) cleanText = cleanText.substring(start, end + 1);
}

let sc;
try {
  sc = JSON.parse(cleanText);
} catch (e) {
  throw new Error('Failed to parse LLM scorecard: ' + responseText.substring(0, 300));
}

if (typeof sc.overall_score !== 'number') sc.overall_score = 0;
if (!Array.isArray(sc.strengths)) sc.strengths = [];
if (!Array.isArray(sc.improvements)) sc.improvements = [];
if (!sc.summary) sc.summary = '';

const allEvidence = [];

for (const s of sc.strengths) {
  if (s.evidence_quote) allEvidence.push({ criterion_key: s.criterion, quote: s.evidence_quote, timestamp_seconds: s.timestamp_seconds || null });
}
for (const s of sc.improvements) {
  if (s.evidence_quote) allEvidence.push({ criterion_key: s.criterion, quote: s.evidence_quote, timestamp_seconds: s.timestamp_seconds || null });
}

if (sc.meeting_phase) allEvidence.push({ criterion_key: 'meeting_phase', quote: String(sc.meeting_phase).trim(), timestamp_seconds: null });

for (const a of (sc.attendees || [])) allEvidence.push({ criterion_key: 'attendee', quote: String(a), timestamp_seconds: null });

if (sc.talk_time_breakdown && sc.talk_time_breakdown.length > 0) {
  allEvidence.push({ criterion_key: 'talk_time_breakdown', quote: JSON.stringify(sc.talk_time_breakdown), timestamp_seconds: null });
}

const LISTS = [
  ['key_points','key_point'],['decisions','decision'],['action_items','action_item'],
  ['next_steps','next_step'],['open_questions','open_question'],['risks','risk'],
  ['suggestions','suggestion'],['projects','project'],['banned_phrases','banned_phrase']
];
for (const [field, key] of LISTS) {
  for (const item of (sc[field] || [])) allEvidence.push({ criterion_key: key, quote: String(item), timestamp_seconds: null });
}

for (const p of (sc.coaching_priorities || [])) {
  if (p.priority >= 1 && p.priority <= 3) allEvidence.push({ criterion_key: 'coaching_priority_' + p.priority, quote: JSON.stringify(p), timestamp_seconds: null });
}

if (sc.meeting_effectiveness) allEvidence.push({ criterion_key: 'meeting_effectiveness', quote: JSON.stringify(sc.meeting_effectiveness), timestamp_seconds: null });

// Store new agent fields as evidence
if (sc.manager_summary) allEvidence.push({ criterion_key: 'manager_summary', quote: String(sc.manager_summary), timestamp_seconds: null });
if (sc.positive_reinforcement) allEvidence.push({ criterion_key: 'positive_reinforcement', quote: String(sc.positive_reinforcement), timestamp_seconds: null });
if (sc.rep_trajectory) allEvidence.push({ criterion_key: 'rep_trajectory', quote: String(sc.rep_trajectory), timestamp_seconds: null });
if (sc.comparison_note) allEvidence.push({ criterion_key: 'comparison_note', quote: String(sc.comparison_note), timestamp_seconds: null });

return [{ json: {
  call_id: callId,
  rubric_id: rubric ? rubric.id : null,
  overall_score: Math.round(sc.overall_score * 10) / 10,
  summary: sc.summary,
  strengths: sc.strengths,
  improvements: sc.improvements,
  llm_model: 'claude-sonnet-4-6',
  all_evidence: allEvidence
} }];

const scorecardRow = ($('Insert Scorecard').first().json || [])[0];
const scorecardId = scorecardRow ? scorecardRow.id : null;
const allEvidence = $('Parse Scorecard').first().json.all_evidence || [];
if (!scorecardId || allEvidence.length === 0) return [{ json: { __skip_evidence: true } }];
const evidenceRows = allEvidence.map(e => ({ scorecard_id: scorecardId, criterion_key: e.criterion_key, quote: e.quote, timestamp_seconds: e.timestamp_seconds }));
return [{ json: { evidence: evidenceRows } }];
